const now = new Date();
const d6m = new Date(now); d6m.setDate(now.getDate() - 180);
const fmt = d => parseInt(`${d.getFullYear()}${String(d.getMonth()+1).padStart(2,'0')}${String(d.getDate()).padStart(2,'0')}`);
return [{ json: { fecha: fmt(d6m), rango: 3 } }];

